#include<bits/stdc++.h>
using namespace std;
long long ans[55],a,b,n=2;
bool isyes=false;
bool f(long long x){ 
	if(x==1)return false;
	if(x==2)return true;
	for(long long i=2;i*i<=x;i++)if(x%i==0)return false;
	return true;
}
void dfs(long long x,long long y,int t){
	if(isyes)return; 
	if(f(abs(x-y))){
    	cout<<t+1<<'\n'; 
    	cout<<a<<' ';
    	for(int i=1;i<t;i++)cout<<ans[i]<<' ';
    	cout<<b<<'\n';
    	isyes=true;return;
	}if(x!=2)
		for(int i=1;i<=3;i++){
			if(i==1&&f(x-2)){ans[t]=2;dfs(2,y,t+1);} 
			if(i==2&&f(x-2)){ans[t]=x-2;dfs(x-2,y,t+1);}
			if(i==3&&f(x+2)){ans[t]=x+2;dfs(x+2,y,t+1);}
		}
	else{
		if(f(y+2)){
			ans[t]=y+2;
			dfs(y+2,y,t+1);
		}
	}
}
void input(){
	cin>>a>>b;
}
void print(){
    if(f(abs(a-b))){ 
    	cout<<n<<'\n'<<a<<' '<<b;
    	return;
	}dfs(a,b,1); 
    if(!isyes)cout<<"-1";
}
int main(void){
	ios::sync_with_stdio(false); 
	input();print();	
	return false; 
}
